"""Aggiunge traduzioni IT al file risorse/classi/class_translations.json."""
import json
from pathlib import Path

PATH = Path("risorse/classi/class_translations.json")

NEW_TRANSLATIONS: dict[str, str] = {
    # ============= PALADIN =============
    "paladin::Divine Sense": "La presenza di un male potente si registra sui tuoi sensi come un odore nauseante, e una potente bontà suona come musica celeste alle tue orecchie. Come azione, puoi aprire la tua consapevolezza per percepire tali forze. Fino alla fine del tuo prossimo turno, conosci la posizione di qualsiasi celestiale, immondo o non morto entro 18 metri da te che non sia dietro copertura totale. Conosci il tipo (celestiale, immondo o non morto) di qualsiasi essere la cui presenza percepisci, ma non la sua identità (per esempio, il vampiro Lord Conte Strahd von Zarovich). Entro la stessa gittata, percepisci anche la presenza di qualsiasi luogo o oggetto che è stato consacrato o sconsacrato, come con l'incantesimo santificare.\nPuoi usare questo privilegio un numero di volte pari a 1 + il tuo modificatore di Carisma. Quando termini un riposo lungo, recuperi tutti gli usi consumati.",
    "paladin::Lay on Hands": "Le tue mani benedette possono curare le ferite. Hai un pool di potere curativo che si reintegra quando ti riposi. Con quel pool, puoi ripristinare un numero totale di punti ferita pari al tuo livello da paladino × 5.\nCome azione, puoi toccare una creatura ed estrarre potere dal pool per ripristinare un numero di punti ferita a quella creatura, fino al massimo rimanente nel tuo pool.\nIn alternativa, puoi spendere 5 punti ferita dal tuo pool di potere curativo per curare il bersaglio da una malattia o neutralizzare un veleno che lo affligge. Puoi curare più malattie e neutralizzare più veleni con un singolo uso di Imposizione delle Mani, spendendo punti ferita separatamente per ognuno.\nQuesto privilegio non ha effetto su non morti e costrutti.",
    "paladin::Fighting Style": "Al 2° livello, adotti uno stile particolare di combattimento come tua specialità. Scegli una delle seguenti opzioni. Non puoi prendere uno Stile di Combattimento più di una volta, anche se in seguito ottieni la possibilità di scegliere di nuovo.\nDifesa: Mentre indossi un'armatura, ottieni un bonus di +1 alla CA.\nDuellare: Quando impugni un'arma da mischia in una mano e nessun'altra arma, ottieni un bonus di +2 ai tiri per i danni con quell'arma.\nCombattere con Armi Grandi: Quando ottieni 1 o 2 sui dadi per i danni di un attacco effettuato con un'arma da mischia che brandisci a due mani, puoi ritirare il dado e devi usare il nuovo tiro. L'arma deve avere la proprietà a due mani o versatile per ottenere questo beneficio.\nProtezione: Quando una creatura che puoi vedere attacca un bersaglio diverso da te entro 1,5 metri da te, puoi usare la tua reazione per imporre svantaggio al tiro per colpire. Devi brandire uno scudo.",
    "paladin::Spellcasting": "Al 2° livello, hai imparato ad attingere magia divina attraverso meditazione e preghiera per lanciare incantesimi come un chierico. Vedi il capitolo 10 per le regole generali sull'uso degli incantesimi e il capitolo 11 per la lista degli incantesimi del paladino.\nPreparare e Lanciare Incantesimi: La tabella del Paladino mostra quanti slot incantesimo possiedi per lanciare i tuoi incantesimi. Per lanciare uno dei tuoi incantesimi del paladino del 1° livello o superiore, devi consumare uno slot del livello dell'incantesimo o di livello superiore. Recuperi tutti gli slot incantesimo consumati quando completi un riposo lungo.\nPrepari la lista degli incantesimi del paladino che ti sono disponibili da lanciare, scegliendoli dalla lista degli incantesimi del paladino. Quando lo fai, scegli un numero di incantesimi del paladino pari al tuo modificatore di Carisma + metà del tuo livello da paladino, arrotondato per difetto (minimo un incantesimo). Gli incantesimi devono essere di un livello per il quale possiedi slot incantesimo.\nPer esempio, se sei un paladino del 5° livello, hai quattro slot incantesimo del 1° livello e due del 2° livello. Con un Carisma di 14, la tua lista di incantesimi preparati può includere quattro incantesimi del 1° o 2° livello, in qualsiasi combinazione. Se prepari l'incantesimo di 1° livello cura ferite, puoi lanciarlo usando uno slot del 1° o del 2° livello. Lanciare l'incantesimo non lo rimuove dalla lista degli incantesimi preparati.\nPuoi cambiare la tua lista di incantesimi preparati al termine di un riposo lungo. Preparare una nuova lista di incantesimi del paladino richiede tempo speso a pregare e meditare: almeno 1 minuto per livello dell'incantesimo per ogni incantesimo nella tua lista.\nCaratteristica da Incantatore: Carisma è la tua caratteristica da incantatore per i tuoi incantesimi del paladino, dato che il loro potere proviene dalla forza delle tue convinzioni. Usi il Carisma ogni volta che un incantesimo si riferisce alla tua caratteristica da incantatore. Inoltre, usi il modificatore di Carisma quando determini la CD dei tiri salvezza per un incantesimo del paladino che lanci e quando effettui un tiro per colpire con un incantesimo.\nCD del Tiro Salvezza dell'Incantesimo = 8 + il tuo bonus di competenza + il tuo modificatore di Carisma\nModificatore di Attacco dell'Incantesimo = il tuo bonus di competenza + il tuo modificatore di Carisma\nFocus per Incantesimi: Puoi usare un simbolo sacro (vedi capitolo 5, \"Equipaggiamento\") come focus per incantesimi per i tuoi incantesimi del paladino.",
    "paladin::Divine Smite": "A partire dal 2° livello, quando colpisci una creatura con un attacco con arma da mischia, puoi spendere uno slot incantesimo per infliggere danni radianti al bersaglio, in aggiunta ai danni dell'arma. I danni extra sono 2d8 per uno slot incantesimo del 1° livello, più 1d8 per ogni livello dell'incantesimo superiore al 1° fino a un massimo di 5d8. I danni aumentano di 1d8 se il bersaglio è un non morto o un immondo, fino a un massimo di 6d8.",
    "paladin::Divine Health": "Al 3° livello, la magia divina che scorre attraverso di te ti rende immune alle malattie.",
    "paladin::Sacred Oath": "Quando raggiungi il 3° livello, fai voto che ti collega a un giuramento sacro come paladino. Fino a questo punto, sei stato in uno stadio preparatorio, impegnato sul cammino ma non ancora vincolato. Ora scegli il Giuramento di Devozione, il Giuramento degli Antichi o il Giuramento della Vendetta, tutti dettagliati alla fine della descrizione della classe.\nLa tua scelta ti garantisce privilegi al 3° livello e di nuovo al 7°, 15° e 20° livello. Quei privilegi includono incantesimi del giuramento e il privilegio Incanalare Divinità.",
    "paladin::Ability Score Improvement": "Quando raggiungi il 4° livello, e di nuovo all'8°, 12°, 16° e 19° livello, puoi aumentare di 2 un punteggio di caratteristica a tua scelta o aumentare di 1 due punteggi di caratteristica a tua scelta. Come al solito, non puoi aumentare un punteggio di caratteristica oltre il 20 utilizzando questo privilegio.",
    "paladin::Extra Attack": "A partire dal 5° livello, puoi attaccare due volte, invece di una, ogni volta che esegui l'azione di Attacco nel tuo turno.",
    "paladin::Aura of Protection": "A partire dal 6° livello, ogni volta che tu o una creatura amichevole entro 3 metri da te dovete effettuare un tiro salvezza, la creatura ottiene un bonus al tiro salvezza pari al tuo modificatore di Carisma (con un bonus minimo di +1). Devi essere cosciente per concedere questo bonus.\nAl 18° livello, la gittata di questa aura aumenta a 9 metri.",
    "paladin::Aura of Courage": "A partire dal 10° livello, tu e le creature amichevoli entro 3 metri da te non potete essere spaventati mentre sei cosciente.\nAl 18° livello, la gittata di questa aura aumenta a 9 metri.",
    "paladin::Improved Divine Smite": "Per il 11° livello, sei così imbevuto di potere giusto che tutti i tuoi colpi in mischia trasportano potere divino con sé. Ogni volta che colpisci una creatura con un'arma da mischia, la creatura subisce 1d8 danni radianti aggiuntivi.",
    "paladin::Cleansing Touch": "A partire dal 14° livello, puoi usare la tua azione per terminare un incantesimo su di te o su una creatura consenziente che tocchi.\nPuoi usare questo privilegio un numero di volte pari al tuo modificatore di Carisma (un minimo di una volta). Recuperi gli usi consumati quando termini un riposo lungo.",
    # — Oath of Devotion —
    "paladin::sub::oath-of-devotion::Tenets of Devotion": "Sebbene la formulazione esatta e i precetti del Giuramento di Devozione possano variare, i paladini di questo giuramento condividono questi principi.\nOnestà. Non mentire né ingannare. Lascia che la tua parola sia la tua promessa.\nCoraggio. Non aver mai paura di agire, sebbene la cautela sia saggia.\nCompassione. Aiuta gli altri, proteggi i deboli e punisci coloro che li minacciano. Mostra clemenza ai tuoi nemici, ma temperala con saggezza.\nOnore. Tratta gli altri con equità, e lascia che le tue azioni onorevoli siano un esempio per loro. Fai il maggior bene possibile, causando il minor danno possibile.\nDovere. Sii responsabile delle tue azioni e delle loro conseguenze, proteggi quelli affidati alla tua cura e obbedisci a coloro che hanno una giusta autorità su di te.",
    "paladin::sub::oath-of-devotion::Oath Spells": "Ottieni gli incantesimi del giuramento ai livelli da paladino indicati.\n3° livello: protezione dal male e dal bene, santuario\n5° livello: zona di verità, fascino su persone\n9° livello: fiamma vendicatrice, dissolvi magie\n13° livello: scudo della fede, libertà di movimento\n17° livello: comando superiore, ristorare superiore",
    "paladin::sub::oath-of-devotion::Channel Divinity": "Quando prendi questo giuramento al 3° livello, ottieni le seguenti due opzioni di Incanalare Divinità.\nArma Sacra. Come azione, imbui un'arma che brandisci con energia positiva, usando il tuo Incanalare Divinità. Per 1 minuto, aggiungi il tuo modificatore di Carisma ai tiri per colpire effettuati con quell'arma (con un bonus minimo di +1). L'arma emette anche luce intensa in un raggio di 6 metri e luce fioca per altri 6 metri. Se l'arma non è già magica, diventa magica per la durata.\nPuoi terminare questo effetto nel tuo turno come parte di qualsiasi altra azione. Se non sei più in grado di brandire l'arma, l'effetto termina.\nScacciare l'Empio. Come azione, presenti il tuo simbolo sacro e pronunci una preghiera che condanna immondi e non morti, usando il tuo Incanalare Divinità. Ogni immondo o non morto che può vederti o sentirti entro 9 metri da te deve effettuare un tiro salvezza su Saggezza. Se la creatura fallisce il tiro salvezza, è scacciata per 1 minuto o finché non subisce danni.\nUna creatura scacciata deve spendere i suoi turni per cercare di allontanarsi il più possibile da te, e non può muoversi volontariamente in uno spazio entro 9 metri da te. Inoltre, non può effettuare reazioni. Per la sua azione, può usare solo l'azione di Scatto o cercare di sfuggire da un effetto che le impedisce di muoversi. Se non c'è nessun posto dove muoversi, la creatura può usare l'azione di Schivata.",
    "paladin::sub::oath-of-devotion::Aura of Devotion": "A partire dal 7° livello, tu e le creature amichevoli entro 3 metri da te non potete essere ammaliati mentre sei cosciente.\nAl 18° livello, la gittata di questa aura aumenta a 9 metri.",
    "paladin::sub::oath-of-devotion::Purity of Spirit": "A partire dal 15° livello, sei sempre sotto gli effetti di un incantesimo protezione dal male e dal bene.",
    "paladin::sub::oath-of-devotion::Holy Nimbus": "Al 20° livello, come azione, puoi emanare un'aura di luce solare. Per 1 minuto, una luce solare intensa risplende da te in un raggio di 9 metri, e luce fioca splende a 18 metri oltre.\nOgni volta che una creatura nemica inizia il proprio turno nella luce intensa, la creatura subisce 10 danni radianti.\nInoltre, per la durata, hai vantaggio ai tiri salvezza contro gli incantesimi lanciati da immondi o non morti.\nUna volta usato questo privilegio, non puoi usarlo di nuovo finché non termini un riposo lungo.",

    # ============= RANGER =============
    "ranger::Favored Enemy": "A partire dal 1° livello, hai una significativa esperienza nello studio, tracciamento, caccia e perfino conversazione con un certo tipo di nemico.\nScegli un tipo di nemico prescelto: aberrazioni, bestie, celestiali, costrutti, draghi, elementali, immondi, folletti, giganti, melme, non morti o piante. In alternativa, puoi selezionare due razze di umanoide (come gnoll e orchi) come tuoi nemici prescelti.\nHai vantaggio alle prove di Saggezza (Sopravvivenza) per tracciare i tuoi nemici prescelti, oltre che alle prove di Intelligenza per ricordare informazioni su di essi.\nQuando ottieni questo privilegio, impari anche una lingua a tua scelta che parla il tuo nemico prescelto, se ne parla una.\nScegli un nemico prescelto aggiuntivo, oltre a una lingua associata, al 6° e al 14° livello. Mentre acquisisci livelli, le tue scelte dovrebbero riflettere i tipi di mostri che hai incontrato nelle tue avventure.",
    "ranger::Natural Explorer": "Sei particolarmente abile nel viaggiare e sopravvivere in certi tipi di terreno. Scegli un tipo di terreno preferito: artico, costa, deserto, foresta, prateria, montagna, palude o Underdark. Quando effettui una prova di Intelligenza o Saggezza relativa al tuo terreno preferito, il tuo bonus di competenza è raddoppiato se stai usando un'abilità in cui sei competente.\nMentre viaggi per un'ora o più nel tuo terreno preferito, ottieni i seguenti benefici:\n* Il terreno difficile non rallenta il viaggio del tuo gruppo.\n* Il tuo gruppo non può essere perso, salvo per mezzi magici.\n* Anche quando sei impegnato in altre attività mentre viaggi (come cercare cibo, navigare o tracciare), rimani comunque in allerta per il pericolo.\n* Se viaggi da solo, puoi muoverti furtivamente a un ritmo normale.\n* Quando cerchi cibo, trovi il doppio del cibo che troveresti normalmente.\n* Mentre tracci altre creature, impari anche il loro numero esatto, le loro taglie e da quanto tempo sono passate per l'area.\nScegli un terreno preferito aggiuntivo al 6° e al 10° livello.",
    "ranger::Fighting Style": "Al 2° livello, adotti uno stile particolare di combattimento come tua specialità. Scegli una delle seguenti opzioni. Non puoi prendere uno Stile di Combattimento più di una volta, anche se in seguito ottieni la possibilità di scegliere di nuovo.\nArcheria: Ottieni un bonus di +2 ai tiri per colpire effettuati con armi a distanza.\nDifesa: Mentre indossi un'armatura, ottieni un bonus di +1 alla CA.\nDuellare: Quando impugni un'arma da mischia in una mano e nessun'altra arma, ottieni un bonus di +2 ai tiri per i danni con quell'arma.\nCombattere con Due Armi: Quando combatti con due armi, puoi aggiungere il tuo modificatore di caratteristica ai danni del secondo attacco.",
    "ranger::Spellcasting": "Quando raggiungi il 2° livello, hai imparato ad usare l'essenza magica della natura per lanciare incantesimi, in modo simile a un druido. Vedi il capitolo 10 per le regole generali sull'uso degli incantesimi e il capitolo 11 per la lista degli incantesimi del ranger.\nSlot Incantesimo: La tabella del Ranger mostra quanti slot incantesimo possiedi per lanciare i tuoi incantesimi del 1° livello e superiori. Per lanciare uno di questi incantesimi, devi consumare uno slot del livello dell'incantesimo o di livello superiore. Recuperi tutti gli slot incantesimo consumati quando completi un riposo lungo.\nPer esempio, se conosci l'incantesimo di 1° livello dardo animale e hai un slot del 1° livello e uno del 2° livello disponibili, puoi lanciare dardo animale usando entrambi.\nIncantesimi Conosciuti del 1° Livello e Superiori: Conosci due incantesimi del 1° livello a tua scelta dalla lista degli incantesimi del ranger.\nLa colonna Incantesimi Conosciuti della tabella del Ranger mostra quando impari altri incantesimi del ranger a tua scelta. Ognuno di questi incantesimi deve essere di un livello per il quale possiedi slot incantesimo. Per esempio, quando raggiungi il 5° livello in questa classe, puoi imparare un nuovo incantesimo del 1° o del 2° livello.\nInoltre, quando ottieni un livello in questa classe, puoi scegliere uno degli incantesimi del ranger che conosci e sostituirlo con un altro incantesimo dalla lista del ranger, anch'esso di un livello per il quale possiedi slot incantesimo.\nCaratteristica da Incantatore: Saggezza è la tua caratteristica da incantatore per i tuoi incantesimi del ranger, dato che la tua magia attinge alla tua sintonia con la natura. Usi la Saggezza ogni volta che un incantesimo si riferisce alla tua caratteristica da incantatore. Inoltre, usi il modificatore di Saggezza quando determini la CD dei tiri salvezza per un incantesimo del ranger che lanci e quando effettui un tiro per colpire con un incantesimo.\nCD del Tiro Salvezza dell'Incantesimo = 8 + il tuo bonus di competenza + il tuo modificatore di Saggezza\nModificatore di Attacco dell'Incantesimo = il tuo bonus di competenza + il tuo modificatore di Saggezza",
    "ranger::Ranger Archetype": "Al 3° livello, scegli un archetipo che ti sforzi di emulare: il Cacciatore o il Maestro delle Bestie, entrambi dettagliati alla fine della descrizione della classe. La tua scelta ti garantisce privilegi al 3° livello e di nuovo al 7°, 11° e 15° livello.",
    "ranger::Primeval Awareness": "A partire dal 3° livello, puoi usare la tua azione e spendere uno slot incantesimo del ranger per concentrarti sul mondo naturale intorno a te ed apprendere alcune informazioni. Per 1 minuto per livello dello slot incantesimo che spendi, puoi percepire se i seguenti tipi di creature sono presenti entro 1,5 km da te (o entro 9 km se sei nel tuo terreno preferito): aberrazioni, celestiali, draghi, elementali, immondi, folletti, non morti. Questo privilegio non rivela la posizione delle creature o il loro numero.",
    "ranger::Ability Score Improvement": "Quando raggiungi il 4° livello, e di nuovo all'8°, 12°, 16° e 19° livello, puoi aumentare di 2 un punteggio di caratteristica a tua scelta o aumentare di 1 due punteggi di caratteristica a tua scelta. Come al solito, non puoi aumentare un punteggio di caratteristica oltre il 20 utilizzando questo privilegio.",
    "ranger::Extra Attack": "A partire dal 5° livello, puoi attaccare due volte, invece di una, ogni volta che esegui l'azione di Attacco nel tuo turno.",
    "ranger::Land's Stride": "A partire dall'8° livello, muoversi attraverso terreni difficili non magici non ti costa movimento extra. Puoi anche attraversare piante non magiche senza essere rallentato da esse e senza subire danni se hanno spine, aculei o simili pericoli.\nInoltre, hai vantaggio ai tiri salvezza contro piante create magicamente o manipolate per impedire il movimento, come quelle create dall'incantesimo intralciare.",
    "ranger::Hide in Plain Sight": "A partire dal 10° livello, puoi spendere 1 minuto creando una mimetizzazione per te stesso. Devi avere accesso a fango, sporco, piante, fuliggine e altri materiali naturali con cui creare la mimetizzazione.\nUna volta mimetizzato in questo modo, puoi cercare di nasconderti premendoti contro una superficie solida, come un albero o una parete, almeno alta e larga quanto te. Ottieni un bonus di +10 alle prove di Destrezza (Furtività) finché rimani lì senza muoverti o effettuare azioni. Una volta che ti muovi o effettui un'azione o una reazione, devi mimetizzarti di nuovo per ottenere questo beneficio.",
    "ranger::Vanish": "A partire dal 14° livello, puoi usare l'azione di Nascondersi come azione bonus nel tuo turno. Inoltre, non puoi essere tracciato con mezzi non magici, a meno che tu non scelga di lasciare una traccia.",
    "ranger::Feral Senses": "Al 18° livello, ottieni sensibilità preternaturali che ti aiutano a combattere creature che non puoi vedere. Quando attacchi una creatura che non puoi vedere, la tua incapacità di vederla non impone svantaggio ai tuoi tiri per colpire contro di essa.\nSei anche consapevole della posizione di qualsiasi creatura invisibile entro 9 metri da te, a condizione che la creatura non sia nascosta da te e tu non sia accecato o assordato.",
    "ranger::Foe Slayer": "Al 20° livello, diventi un cacciatore senza pari dei tuoi nemici. Una volta in ognuno dei tuoi turni, puoi aggiungere il tuo modificatore di Saggezza al tiro per colpire o al tiro per i danni di un attacco effettuato contro uno dei tuoi nemici prescelti. Puoi scegliere di usare questo privilegio prima o dopo il tiro, ma prima di sapere se il tiro abbia successo o no.",
    # — Hunter —
    "ranger::sub::hunter::Hunter's Prey": "Al 3° livello, ottieni uno dei seguenti privilegi a tua scelta.\nUccisore di Colossi. La tua tenacia ti permette di smantellare gli avversari più potenti. Quando colpisci una creatura con un attacco con un'arma, la creatura subisce 1d8 danni extra se è al di sotto del suo punteggio di punti ferita massimo. Puoi infliggere questi danni extra una sola volta per turno.\nDifesa Gigante. Quando viene colpito da una creatura Grande o più grande di te entro 1,5 metri, puoi usare la tua reazione per dimezzare i danni dell'attacco contro di te.\nUccisore di Sciami. Sei abile nel combattere contro molti avversari. Una volta in ognuno dei tuoi turni quando colpisci una creatura con un'arma, la creatura subisce 1d8 danni extra se è entro 1,5 metri da un'altra creatura non incapacitata che non sia tua compagna.",
    "ranger::sub::hunter::Defensive Tactics": "Al 7° livello, ottieni uno dei seguenti privilegi a tua scelta.\nFurtività dei Sensi. Le creature non hanno vantaggio ai tiri per colpire contro di te come risultato dell'essere nascoste da te.\nDifesa Multiattacco. Quando una creatura ti colpisce con un attacco, ottieni un bonus di +4 alla CA contro tutti i successivi attacchi effettuati da quella creatura per il resto del turno.\nDifensore della Fauna. Hai vantaggio ai tiri salvezza contro effetti di ammaliamento e spavento di bestie e piante.",
    "ranger::sub::hunter::Multiattack": "All'11° livello, ottieni uno dei seguenti privilegi a tua scelta.\nRaffica. Puoi usare la tua azione per attaccare due volte ogni creatura entro 3 metri da un punto che puoi vedere entro la gittata della tua arma con un attacco a distanza.\nAttacco Roteante. Puoi usare la tua azione per effettuare un attacco con arma da mischia contro qualsiasi numero di creature entro 1,5 metri da te, con un attacco separato per ognuna di esse.",
    "ranger::sub::hunter::Superior Hunter's Defense": "Al 15° livello, ottieni uno dei seguenti privilegi a tua scelta.\nElusione. Quando sei sottoposto a un effetto, come il soffio infuocato di un drago rosso o un incantesimo palla di fuoco, che permette di effettuare un tiro salvezza su Destrezza per dimezzare i danni, non subisci danni se superi il tiro salvezza, e solo metà dei danni se lo fallisci.\nRappresaglia. Quando subisci danni da una creatura entro 1,5 metri da te, puoi usare la tua reazione per effettuare un attacco in mischia contro la creatura.\nResistenza dello Sterminatore di Sciami. Quando subisci danni da una creatura, ottieni resistenza a tutti i danni inflitti dalle altre creature fino all'inizio del tuo prossimo turno.",

    # ============= ROGUE =============
    "rogue::Expertise": "Al 1° livello, scegli due delle tue competenze in abilità, o una delle tue competenze in abilità e la tua competenza con gli arnesi da scasso. Il tuo bonus di competenza è raddoppiato per ogni prova di caratteristica che effettui che usi una di queste competenze prescelte.\nAl 6° livello, puoi scegliere altre due competenze (in abilità o con gli arnesi da scasso) per ottenere il beneficio di questo privilegio.",
    "rogue::Sneak Attack": "A partire dal 1° livello, sai come colpire sottilmente e sfruttare la distrazione di un nemico. Una volta per turno, puoi infliggere 1d6 danni extra a una creatura che colpisci con un attacco se hai vantaggio al tiro per colpire. L'attacco deve usare un'arma da finezza o a distanza.\nNon hai bisogno di vantaggio al tiro per colpire se un'altra nemica del bersaglio è entro 1,5 metri da esso, quella creatura non è incapacitata e tu non hai svantaggio al tiro per colpire.\nL'ammontare dei danni extra aumenta man mano che acquisisci livelli in questa classe, come mostrato nella colonna Attacco Furtivo della tabella del Ladro.",
    "rogue::Thieves' Cant": "Durante il tuo allenamento da ladro, hai imparato il gergo dei ladri, una mistura segreta di dialetto, gergo e codice che ti permette di nascondere messaggi in conversazioni apparentemente normali. Solo un'altra creatura che conosce il gergo dei ladri capisce tali messaggi. Ci vogliono quattro volte tanto a comunicare un tale messaggio rispetto a un linguaggio normale.\nInoltre, comprendi un set di simboli e segni segreti usati per trasmettere messaggi brevi e semplici, come ad esempio se un'area è pericolosa o il territorio di una corporazione di ladri, se il bottino è vicino o se le persone in un'area sono creduloni o forze dell'ordine.",
    "rogue::Cunning Action": "A partire dal 2° livello, la tua agilità mentale e fisica veloce ti permette di muoverti e agire rapidamente. Puoi compiere un'azione bonus in ognuno dei tuoi turni in combattimento. Quell'azione può essere usata solo per effettuare l'azione di Scatto, Disimpegnarsi o Nascondersi.",
    "rogue::Roguish Archetype": "Al 3° livello, scegli un archetipo che illustra il tuo metodo di lavoro: Ladro, Assassino o Stregone Arcano, tutti dettagliati alla fine della descrizione della classe. La tua scelta archetipale ti garantisce privilegi al 3° livello e di nuovo al 9°, 13° e 17° livello.",
    "rogue::Ability Score Improvement": "Quando raggiungi il 4° livello, e di nuovo all'8°, 10°, 12°, 16° e 19° livello, puoi aumentare di 2 un punteggio di caratteristica a tua scelta o aumentare di 1 due punteggi di caratteristica a tua scelta. Come al solito, non puoi aumentare un punteggio di caratteristica oltre il 20 utilizzando questo privilegio.",
    "rogue::Uncanny Dodge": "A partire dal 5° livello, quando un attaccante che puoi vedere ti colpisce con un attacco, puoi usare la tua reazione per dimezzare i danni dell'attacco contro di te.",
    "rogue::Evasion": "A partire dal 7° livello, puoi sgusciare via dagli effetti di area, come il soffio infuocato di un drago rosso o un incantesimo fulmine. Quando sei sottoposto a un effetto che permette di effettuare un tiro salvezza su Destrezza per dimezzare i danni, non subisci danni se superi il tiro salvezza, e solo metà dei danni se lo fallisci.",
    "rogue::Reliable Talent": "Per l'11° livello, hai affinato le tue abilità prescelte fino a raggiungere la perfezione. Ogni volta che effettui una prova di caratteristica che ti permette di aggiungere il tuo bonus di competenza, puoi trattare un tiro di 9 o inferiore sul d20 come 10.",
    "rogue::Blindsense": "A partire dal 14° livello, se sei in grado di sentire, sei consapevole della posizione di qualsiasi creatura nascosta o invisibile entro 3 metri da te.",
    "rogue::Slippery Mind": "Per il 15° livello, hai acquisito una resilienza mentale superiore. Ottieni la competenza nei tiri salvezza su Saggezza.",
    "rogue::Elusive": "A partire dal 18° livello, sei così sfuggente che gli attaccanti raramente ottengono il sopravvento contro di te. Nessun tiro per colpire ha vantaggio contro di te mentre non sei incapacitato.",
    "rogue::Stroke of Luck": "Al 20° livello, hai un'abilità incomparabile nel cogliere il successo dal fallimento. Se il tuo attacco fallisce contro un bersaglio entro la tua gittata, puoi trasformare il fallimento in un successo. In alternativa, se fallisci una prova di caratteristica, puoi trattare il d20 come se avessi ottenuto un 20.\nUna volta usato questo privilegio, non puoi usarlo di nuovo finché non termini un riposo breve o lungo.",
    # — Thief —
    "rogue::sub::thief::Fast Hands": "A partire dal 3° livello, puoi usare l'azione bonus concessa dalla tua Azione Scaltra per effettuare una prova di Destrezza (Rapidità di Mano), usare i tuoi arnesi da scasso per disinnescare una trappola o aprire una serratura, o effettuare l'azione di Usare un Oggetto.",
    "rogue::sub::thief::Second-Story Work": "Quando scegli questo archetipo al 3° livello, ottieni la capacità di arrampicarti più velocemente del normale; arrampicarsi non ti costa più movimento extra.\nInoltre, quando effettui un salto in lungo da fermo, la distanza che puoi coprire aumenta di un numero di metri pari al tuo modificatore di Destrezza.",
    "rogue::sub::thief::Supreme Sneak": "A partire dal 9° livello, hai vantaggio a una prova di Destrezza (Furtività) se ti muovi a non più della metà della tua velocità nello stesso turno.",
    "rogue::sub::thief::Use Magic Device": "Per il 13° livello, hai imparato abbastanza sul funzionamento della magia da poter improvvisare l'uso di oggetti anche quando non sono destinati a te. Ignori tutte le restrizioni di classe, razza e livello sull'uso di oggetti magici.",
    "rogue::sub::thief::Thief's Reflexes": "Quando raggiungi il 17° livello, sei diventato abile nel colpire prima e sgusciare via prima che gli avversari riescano ad agire. Puoi effettuare due turni durante il primo round di qualsiasi combattimento. Effettui il tuo primo turno con la tua iniziativa normale e il tuo secondo turno con la tua iniziativa meno 10. Non puoi usare questo privilegio quando sei sorpreso.",

    # ============= SORCERER =============
    "sorcerer::Spellcasting": "Un evento nel tuo passato, o nella vita di un genitore o antenato, ti ha lasciato un'impronta indelebile su di te, infondendo magia in te. Questo pozzo di magia, di qualunque sua fonte, alimenta i tuoi incantesimi. Vedi il capitolo 10 per le regole generali sull'uso degli incantesimi e il capitolo 11 per la lista degli incantesimi dello stregone.\nTrucchetti: Al 1° livello, conosci quattro trucchetti a tua scelta dalla lista degli incantesimi dello stregone. Impari trucchetti aggiuntivi dello stregone a livelli successivi, come mostrato nella colonna Trucchetti Conosciuti della tabella dello Stregone.\nSlot Incantesimo: La tabella dello Stregone mostra quanti slot incantesimo possiedi per lanciare i tuoi incantesimi del 1° livello e superiori. Per lanciare uno di questi incantesimi, devi consumare uno slot del livello dell'incantesimo o di livello superiore. Recuperi tutti gli slot incantesimo consumati quando completi un riposo lungo.\nIncantesimi Conosciuti del 1° Livello e Superiori: Conosci due incantesimi del 1° livello a tua scelta dalla lista degli incantesimi dello stregone.\nLa colonna Incantesimi Conosciuti della tabella dello Stregone mostra quando impari altri incantesimi dello stregone a tua scelta. Ognuno di questi incantesimi deve essere di un livello per il quale possiedi slot incantesimo.\nInoltre, quando ottieni un livello in questa classe, puoi scegliere uno degli incantesimi dello stregone che conosci e sostituirlo con un altro incantesimo dalla lista dello stregone, anch'esso di un livello per il quale possiedi slot incantesimo.\nCaratteristica da Incantatore: Carisma è la tua caratteristica da incantatore per i tuoi incantesimi dello stregone, dato che la potenza della tua magia si basa sulla tua capacità di proiettare la tua volontà nel mondo. Usi il Carisma ogni volta che un incantesimo si riferisce alla tua caratteristica da incantatore. Inoltre, usi il modificatore di Carisma quando determini la CD dei tiri salvezza per un incantesimo dello stregone che lanci e quando effettui un tiro per colpire con un incantesimo.\nCD del Tiro Salvezza dell'Incantesimo = 8 + il tuo bonus di competenza + il tuo modificatore di Carisma\nModificatore di Attacco dell'Incantesimo = il tuo bonus di competenza + il tuo modificatore di Carisma\nFocus per Incantesimi: Puoi usare un focus arcano (vedi capitolo 5, \"Equipaggiamento\") come focus per incantesimi per i tuoi incantesimi dello stregone.",
    "sorcerer::Sorcerous Origin": "Scegli un'origine stregonesca, che descrive la fonte del tuo potere magico innato: Stirpe Draconica o Magia Selvaggia, entrambe dettagliate alla fine della descrizione della classe.\nLa tua scelta ti garantisce privilegi quando la scegli al 1° livello e di nuovo al 6°, 14° e 18° livello.",
    "sorcerer::Font of Magic": "Al 2° livello, attingi a un pozzo profondo di magia interna. Questo pozzo è rappresentato da Punti Stregoneria, che ti permettono di creare una varietà di effetti magici.\nPunti Stregoneria. Hai 2 punti stregoneria, e ne ottieni di più man mano che raggiungi i livelli più alti, come mostrato nella colonna Punti Stregoneria della tabella dello Stregone. Non puoi mai avere più punti stregoneria di quelli mostrati sulla tabella per il tuo livello. Recuperi tutti i punti stregoneria consumati quando completi un riposo lungo.\nMetamagia Flessibile. Puoi usare i tuoi punti stregoneria per ottenere slot incantesimo aggiuntivi, o sacrificare slot incantesimo per ottenere punti stregoneria aggiuntivi. Impari altri modi per usare i tuoi punti stregoneria man mano che raggiungi i livelli più alti.\nCreare Slot Incantesimo. Puoi trasformare i punti stregoneria che hai consumato in slot incantesimo come azione bonus nel tuo turno. La Tabella di Creazione degli Slot Incantesimo mostra il costo di creare uno slot incantesimo di un dato livello. Puoi creare slot incantesimo non più alti del 5° livello.\nQualsiasi slot incantesimo crei con questo privilegio scompare alla fine di un riposo lungo.\nConvertire uno Slot Incantesimo in Punti Stregoneria. Come azione bonus nel tuo turno, puoi spendere uno slot incantesimo e ottenere un numero di punti stregoneria pari al livello dello slot.",
    "sorcerer::Metamagic": "Al 3° livello, ottieni la capacità di influenzare e plasmare gli incantesimi. Scegli due delle seguenti opzioni di Metamagia a tua scelta. Ne ottieni un'altra al 10° e al 17° livello.\nPuoi usare solo un'opzione di Metamagia su un incantesimo quando lo lanci, a meno che non sia indicato diversamente.\n[L'elenco completo delle opzioni di Metamagia segue nelle regole]",
    "sorcerer::Ability Score Improvement": "Quando raggiungi il 4° livello, e di nuovo all'8°, 12°, 16° e 19° livello, puoi aumentare di 2 un punteggio di caratteristica a tua scelta o aumentare di 1 due punteggi di caratteristica a tua scelta. Come al solito, non puoi aumentare un punteggio di caratteristica oltre il 20 utilizzando questo privilegio.",
    "sorcerer::Sorcerous Restoration": "Al 20° livello, recuperi 4 punti stregoneria consumati ogni volta che termini un riposo breve.",
    # — Draconic Bloodline —
    "sorcerer::sub::draconic-bloodline::Dragon Ancestor": "Al 1° livello, scegli un tipo di drago come tuo antenato. I danni del tipo associato al tuo antenato sono usati dai privilegi che ottieni successivamente.\nPuoi parlare, leggere e scrivere il Draconico. Inoltre, ogni volta che effettui una prova di Carisma quando interagisci con i draghi, il tuo bonus di competenza è raddoppiato se applicabile alla prova.",
    "sorcerer::sub::draconic-bloodline::Draconic Resilience": "A partire dal 1° livello, mentre la magia scorre attraverso il tuo corpo, manifesta tratti del tuo antenato draconico. I tuoi punti ferita massimi aumentano di 1 e aumentano di 1 ogni volta che ottieni un livello in questa classe.\nInoltre, parti della tua pelle sono coperte da un sottile strato di squame simili a quelle dei draghi. Quando non indossi un'armatura, la tua CA è pari a 13 + il tuo modificatore di Destrezza.",
    "sorcerer::sub::draconic-bloodline::Elemental Affinity": "A partire dal 6° livello, quando lanci un incantesimo che infligge danni del tipo associato al tuo antenato draconico, puoi aggiungere il tuo modificatore di Carisma a un tiro per i danni di quell'incantesimo. Allo stesso tempo, puoi spendere 1 punto stregoneria per ottenere resistenza a quel tipo di danno per 1 ora.",
    "sorcerer::sub::draconic-bloodline::Dragon Wings": "Al 14° livello, ottieni la capacità di far germogliare un paio di ali di drago dalla tua schiena, ottenendo una velocità di volo pari alla tua velocità attuale. Puoi creare queste ali come azione bonus nel tuo turno. Rimangono finché non le congediti come azione bonus nel tuo turno.\nNon puoi manifestare le tue ali mentre indossi un'armatura, a meno che l'armatura non sia stata creata per accomodarle, e gli abiti non destinati a accomodare le ali potrebbero essere rovinati quando emergi.",
    "sorcerer::sub::draconic-bloodline::Draconic Presence": "A partire dal 18° livello, puoi sfruttare la potenza imponente del tuo antenato draconico, facendo sì che gli altri sentano il timore. Come azione, puoi spendere 5 punti stregoneria per emanare un'aura di tremore o di paura (a tua scelta) fino a una distanza di 18 metri. Per 1 minuto o finché non perdi la concentrazione (come se ti stessi concentrando su un incantesimo), ogni creatura ostile che inizia il proprio turno in questa aura deve superare un tiro salvezza su Saggezza o essere ammaliata (se hai scelto tremore) o spaventata (se hai scelto paura) finché l'aura termina. Una creatura che supera il tiro salvezza è immune alla tua aura per 24 ore.",

    # ============= WARLOCK =============
    "warlock::Otherworldly Patron": "Al 1° livello, hai stretto un patto con un essere ultraterreno a tua scelta: l'Arcifolletto, l'Immondo o il Grande Antico, ognuno dei quali è dettagliato alla fine della descrizione della classe. La tua scelta ti garantisce privilegi al 1° livello e di nuovo al 6°, 10° e 14° livello.",
    "warlock::Pact Magic": "Le tue ricerche arcane e la magia conferita dal tuo patrono ti concedono la facilità con gli incantesimi. Vedi il capitolo 10 per le regole generali sull'uso degli incantesimi e il capitolo 11 per la lista degli incantesimi del warlock.\nTrucchetti: Conosci due trucchetti a tua scelta dalla lista degli incantesimi del warlock. Impari trucchetti aggiuntivi a livelli superiori, come mostrato nella colonna Trucchetti Conosciuti della tabella del Warlock.\nSlot Incantesimo: La tabella del Warlock mostra quanti slot incantesimo hai. La tabella mostra anche qual è il livello di quegli slot; tutti i tuoi slot incantesimo sono dello stesso livello. Per lanciare uno dei tuoi incantesimi del warlock del 1° livello o superiori, devi consumare uno slot incantesimo. Recuperi tutti gli slot incantesimo consumati quando termini un riposo breve o lungo.\nPer esempio, quando sei un warlock del 5° livello, hai due slot incantesimo del 3° livello. Per lanciare l'incantesimo del 1° livello dardo incantato, devi consumare uno di quegli slot, e lo lanci come incantesimo del 3° livello.\nIncantesimi Conosciuti del 1° Livello e Superiori: Al 1° livello, conosci due incantesimi del 1° livello a tua scelta dalla lista degli incantesimi del warlock.\nLa colonna Incantesimi Conosciuti della tabella del Warlock mostra quando impari altri incantesimi del warlock a tua scelta del 1° livello e superiori. Un incantesimo che scegli deve essere di un livello pari o inferiore a quello mostrato nella colonna Livello degli Slot della tabella per il tuo livello. Quando raggiungi il 6° livello, per esempio, impari un nuovo incantesimo del warlock, che può essere del 1°, 2° o 3° livello.\nInoltre, quando ottieni un livello in questa classe, puoi scegliere uno degli incantesimi del warlock che conosci e sostituirlo con un altro incantesimo dalla lista del warlock, anch'esso di un livello per il quale possiedi slot incantesimo.\nCaratteristica da Incantatore: Carisma è la tua caratteristica da incantatore per i tuoi incantesimi del warlock, dato che impari i tuoi incantesimi attraverso lo studio dedicato e la memorizzazione, ma li lanci per pura forza di personalità. Usi il Carisma ogni volta che un incantesimo si riferisce alla tua caratteristica da incantatore. Inoltre, usi il modificatore di Carisma quando determini la CD dei tiri salvezza per un incantesimo del warlock che lanci e quando effettui un tiro per colpire con un incantesimo.\nCD del Tiro Salvezza dell'Incantesimo = 8 + il tuo bonus di competenza + il tuo modificatore di Carisma\nModificatore di Attacco dell'Incantesimo = il tuo bonus di competenza + il tuo modificatore di Carisma\nFocus per Incantesimi: Puoi usare un focus arcano (vedi capitolo 5, \"Equipaggiamento\") come focus per incantesimi per i tuoi incantesimi del warlock.",
    "warlock::Eldritch Invocations": "Nei tuoi studi della tradizione occulta, hai dissotterrato invocazioni mistiche, frammenti di conoscenza proibita che ti imbevono di una capacità magica permanente.\nAl 2° livello, ottieni due invocazioni mistiche a tua scelta. Le tue opzioni di invocazione sono dettagliate alla fine della descrizione della classe. Quando ottieni alcuni livelli da warlock, ottieni invocazioni mistiche aggiuntive a tua scelta, come mostrato nella colonna Invocazioni Conosciute della tabella del Warlock.\nInoltre, quando ottieni un livello in questa classe, puoi scegliere una delle invocazioni che conosci e sostituirla con un'altra invocazione che potresti imparare a quel livello.",
    "warlock::Pact Boon": "Al 3° livello, il tuo patrono ultraterreno ti concede un dono per il tuo fedele servizio. Ottieni una delle seguenti opzioni a tua scelta.\nDono della Catena. Impari l'incantesimo trova famiglio e puoi lanciarlo come rituale. L'incantesimo non conta nel numero degli incantesimi che conosci.\nDono della Lama. Puoi usare la tua azione per creare un'arma da patto nella tua mano vuota. Puoi scegliere la forma che assume questa arma da mischia ogni volta che la crei. Sei competente con essa mentre la brandisci. Quest'arma conta come magica per superare la resistenza e l'immunità ad attacchi e danni non magici.\nDono del Tomo. Il tuo patrono ti dà un grimorio chiamato Libro delle Ombre. Quando ottieni questo privilegio, scegli tre trucchetti da qualsiasi lista di incantesimi delle altre classi. Mentre il libro è su di te, puoi lanciare quei trucchetti a piacimento. Non contano nel tuo numero di trucchetti conosciuti.",
    "warlock::Ability Score Improvement": "Quando raggiungi il 4° livello, e di nuovo all'8°, 12°, 16° e 19° livello, puoi aumentare di 2 un punteggio di caratteristica a tua scelta o aumentare di 1 due punteggi di caratteristica a tua scelta. Come al solito, non puoi aumentare un punteggio di caratteristica oltre il 20 utilizzando questo privilegio.",
    "warlock::Mystic Arcanum": "All'11° livello, il tuo patrono ti garantisce un segreto magico chiamato un arcanum. Scegli un incantesimo del 6° livello dalla lista degli incantesimi del warlock come questo arcanum.\nPuoi lanciare il tuo incantesimo arcanum una volta senza spendere uno slot incantesimo. Devi terminare un riposo lungo prima di poterlo lanciare di nuovo.\nA livelli superiori, ottieni più incantesimi del warlock a tua scelta che possono essere lanciati in questo modo: uno del 7° livello al 13° livello, uno dell'8° livello al 15° livello e uno del 9° livello al 17° livello. Recuperi tutti gli usi del tuo Arcanum Mistico quando termini un riposo lungo.",
    "warlock::Eldritch Master": "Al 20° livello, puoi attingere alla tua riserva di potere mistico mentre implori favori dal tuo patrono. Spendi 1 minuto a implorare l'assistenza del tuo patrono per recuperare tutti i tuoi slot incantesimo consumati dal tuo privilegio Magia del Patto. Una volta usato questo privilegio, devi terminare un riposo lungo prima di poterlo usare di nuovo.",
    # — The Fiend —
    "warlock::sub::the-fiend::Expanded Spell List": "L'Immondo ti permette di scegliere tra un elenco esteso di incantesimi quando impari un incantesimo del warlock. I seguenti incantesimi sono aggiunti alla lista degli incantesimi del warlock per te.\n1° livello: comando, gocce di fuoco\n2° livello: cecità/sordità, scurire\n3° livello: dono dell'incoscienza, palla di fuoco\n4° livello: muro di fuoco, peste degli insetti\n5° livello: emanazione tossica, riempire",
    "warlock::sub::the-fiend::Dark One's Blessing": "A partire dal 1° livello, quando riduci una creatura ostile a 0 punti ferita, ottieni punti ferita temporanei pari al tuo modificatore di Carisma + il tuo livello da warlock (minimo 1).",
    "warlock::sub::the-fiend::Dark One's Own Luck": "A partire dal 6° livello, puoi attingere alla fortuna oscura del tuo patrono quando ne hai più bisogno. Quando effettui una prova di caratteristica o un tiro salvezza, puoi usare questo privilegio per aggiungere un d10 al tuo tiro. Puoi farlo dopo aver visto il tiro iniziale ma prima che siano applicate le sue conseguenze.\nUna volta usato questo privilegio, non puoi usarlo di nuovo finché non termini un riposo breve o lungo.",
    "warlock::sub::the-fiend::Fiendish Resilience": "A partire dal 10° livello, puoi scegliere un tipo di danno quando termini un riposo breve o lungo. Ottieni resistenza a quel tipo di danno finché non scegli un tipo diverso con questo privilegio. I danni di armi magiche o argento ignorano questa resistenza.",
    "warlock::sub::the-fiend::Hurl Through Hell": "A partire dal 14° livello, quando colpisci una creatura con un attacco, puoi usare questo privilegio per inviare istantaneamente il bersaglio attraverso i piani inferiori. La creatura scompare e attraversa un incubo paesaggio.\nAlla fine del tuo prossimo turno, il bersaglio ritorna nello spazio che precedentemente occupava, o nello spazio libero più vicino. Se il bersaglio non è un immondo, subisce 10d10 danni psichici dato che riemerge tormentata dalle sue esperienze.\nUna volta usato questo privilegio, non puoi usarlo di nuovo finché non termini un riposo lungo.",

    # ============= WIZARD =============
    "wizard::Spellcasting": "Come studente di magia arcana, hai un grimorio contenente incantesimi che mostrano i primi accenni del tuo vero potere. Vedi il capitolo 10 per le regole generali sull'uso degli incantesimi e il capitolo 11 per la lista degli incantesimi del mago.\nTrucchetti: Al 1° livello, conosci tre trucchetti a tua scelta dalla lista degli incantesimi del mago. Impari trucchetti aggiuntivi a livelli superiori, come mostrato nella colonna Trucchetti Conosciuti della tabella del Mago.\nGrimorio: Al 1° livello, hai un grimorio contenente sei incantesimi del 1° livello a tua scelta dalla lista degli incantesimi del mago.\nPreparare e Lanciare Incantesimi: La tabella del Mago mostra quanti slot incantesimo hai per lanciare i tuoi incantesimi del 1° livello e superiori. Per lanciare uno di questi incantesimi, devi consumare uno slot del livello dell'incantesimo o di livello superiore. Recuperi tutti gli slot incantesimo consumati quando completi un riposo lungo.\nPrepari la lista degli incantesimi del mago che ti sono disponibili da lanciare. Per farlo, scegli un numero di incantesimi del mago dal tuo grimorio pari al tuo modificatore di Intelligenza + il tuo livello da mago (minimo un incantesimo). Gli incantesimi devono essere di un livello per il quale possiedi slot incantesimo.\nPer esempio, se sei un mago del 3° livello, hai quattro slot incantesimo del 1° livello e due del 2° livello. Con un'Intelligenza di 16, la tua lista di incantesimi preparati può includere sei incantesimi del 1° o 2° livello, in qualsiasi combinazione, scelti dal tuo grimorio. Se prepari l'incantesimo di 1° livello dardo incantato, puoi lanciarlo usando uno slot del 1° o del 2° livello. Lanciare l'incantesimo non lo rimuove dalla tua lista degli incantesimi preparati.\nPuoi cambiare la tua lista di incantesimi preparati al termine di un riposo lungo. Preparare una nuova lista di incantesimi del mago richiede tempo speso a studiare il tuo grimorio e memorizzare gli incantesimi: almeno 1 minuto per livello dell'incantesimo per ogni incantesimo nella tua lista.\nCaratteristica da Incantatore: Intelligenza è la tua caratteristica da incantatore per i tuoi incantesimi del mago, dato che impari i tuoi incantesimi attraverso lo studio dedicato e la memorizzazione. Usi l'Intelligenza ogni volta che un incantesimo si riferisce alla tua caratteristica da incantatore. Inoltre, usi il modificatore di Intelligenza quando determini la CD dei tiri salvezza per un incantesimo del mago che lanci e quando effettui un tiro per colpire con un incantesimo.\nCD del Tiro Salvezza dell'Incantesimo = 8 + il tuo bonus di competenza + il tuo modificatore di Intelligenza\nModificatore di Attacco dell'Incantesimo = il tuo bonus di competenza + il tuo modificatore di Intelligenza\nLanciare Rituali: Puoi lanciare un incantesimo del mago come rituale se quell'incantesimo possiede il descrittore di rituale e lo hai nel tuo grimorio. Non hai bisogno di avere l'incantesimo preparato.\nFocus per Incantesimi: Puoi usare un focus arcano (vedi capitolo 5, \"Equipaggiamento\") come focus per incantesimi per i tuoi incantesimi del mago.",
    "wizard::Arcane Recovery": "Hai imparato a recuperare parte della tua energia magica studiando il tuo grimorio. Una volta al giorno quando termini un riposo breve, puoi scegliere gli slot incantesimo consumati da recuperare. Gli slot incantesimo possono avere un livello combinato pari o inferiore alla metà del tuo livello da mago (arrotondato per eccesso), e nessuno degli slot può essere del 6° livello o superiore.\nPer esempio, se sei un mago del 4° livello, puoi recuperare fino a due livelli di slot incantesimo. Puoi recuperare uno slot del 2° livello o due slot del 1° livello.",
    "wizard::Arcane Tradition": "Quando raggiungi il 2° livello, scegli una tradizione arcana, modellando la tua pratica della magia attraverso una di otto scuole: Abiurazione, Ammaliamento, Divinazione, Evocazione, Illusione, Invocazione, Necromanzia o Trasmutazione. La tradizione che scegli ti garantisce privilegi al 2° livello e di nuovo al 6°, 10° e 14° livello.",
    "wizard::Ability Score Improvement": "Quando raggiungi il 4° livello, e di nuovo all'8°, 12°, 16° e 19° livello, puoi aumentare di 2 un punteggio di caratteristica a tua scelta o aumentare di 1 due punteggi di caratteristica a tua scelta. Come al solito, non puoi aumentare un punteggio di caratteristica oltre il 20 utilizzando questo privilegio.",
    "wizard::Spell Mastery": "Al 18° livello, hai raggiunto una tale maestria su determinati incantesimi che puoi lanciarli a piacimento. Scegli un incantesimo del 1° livello e un incantesimo del 2° livello che siano nel tuo grimorio. Puoi lanciare quegli incantesimi al loro livello più basso senza spendere uno slot incantesimo quando li hai preparati. Se vuoi lanciare uno di essi a un livello superiore, devi spendere uno slot incantesimo come al solito.\nLanciando uno studio di 8 ore puoi cambiare uno o entrambi questi incantesimi con incantesimi diversi degli stessi livelli.",
    "wizard::Signature Spells": "Quando raggiungi il 20° livello, ottieni la maestria di due potenti incantesimi e puoi lanciarli con poco sforzo. Scegli due incantesimi del 3° livello nel tuo grimorio come tuoi incantesimi marchiati. Hai sempre questi incantesimi preparati, non contano nel numero degli incantesimi che hai preparato, e puoi lanciarne ognuno una volta al loro livello più basso senza spendere uno slot incantesimo. Quando lo fai, non puoi farlo di nuovo finché non termini un riposo breve o lungo.\nSe vuoi lanciare uno degli incantesimi a un livello superiore, devi spendere uno slot incantesimo come al solito.",
    # — School of Evocation —
    "wizard::sub::school-of-evocation::Evocation Savant": "A partire da quando scegli questa scuola al 2° livello, l'oro e il tempo che devi spendere per copiare un incantesimo di evocazione nel tuo grimorio sono dimezzati.",
    "wizard::sub::school-of-evocation::Sculpt Spells": "A partire dal 2° livello, puoi creare tasche di sicurezza relativa all'interno degli effetti dei tuoi incantesimi di evocazione. Quando lanci un incantesimo di evocazione che influenza altre creature che puoi vedere, puoi scegliere un numero di esse pari a 1 + il livello dell'incantesimo. Le creature scelte superano automaticamente i tiri salvezza contro l'incantesimo, e non subiscono danni se normalmente subirebbero la metà dei danni con un tiro salvezza riuscito.",
    "wizard::sub::school-of-evocation::Potent Cantrip": "A partire dal 6° livello, i tuoi trucchetti danneggianti influenzano anche le creature che eludono il danno. Quando una creatura supera un tiro salvezza contro il tuo trucchetto, la creatura subisce metà dei danni dell'incantesimo (se applicabile) ma non subisce ulteriori effetti dal trucchetto.",
    "wizard::sub::school-of-evocation::Empowered Evocation": "A partire dal 10° livello, puoi aggiungere il tuo modificatore di Intelligenza a un tiro per i danni di qualsiasi incantesimo di evocazione del mago che lanci.",
    "wizard::sub::school-of-evocation::Overchannel": "A partire dal 14° livello, puoi aumentare la potenza dei tuoi incantesimi più semplici. Quando lanci un incantesimo del mago del 1° al 5° livello che infligge danni, puoi infliggere il massimo dei danni con quell'incantesimo.\nLa prima volta che lo fai, non subisci alcun effetto avverso. Se usi questo privilegio di nuovo prima di terminare un riposo lungo, subisci 2d12 danni necrotici per ognuno dei livelli dell'incantesimo, immediatamente dopo aver lanciato l'incantesimo. Ogni volta che usi questo privilegio di nuovo prima di terminare un riposo lungo, i danni necrotici per livello dell'incantesimo aumentano di 1d12. Questi danni ignorano resistenza e immunità.",
}


def main() -> int:
    current = json.loads(PATH.read_text(encoding="utf-8"))
    classes = current.setdefault("classes", {})
    added = 0
    updated = 0
    for key, desc in NEW_TRANSLATIONS.items():
        parts = key.split("::")
        if len(parts) == 2:
            cls_slug, name_en = parts
            cls = classes.setdefault(cls_slug, {})
            feats = cls.setdefault("features", {})
            entry = feats.setdefault(name_en, {})
        elif len(parts) == 4 and parts[1] == "sub":
            cls_slug, _, sub_slug, name_en = parts
            cls = classes.setdefault(cls_slug, {})
            subs = cls.setdefault("subclasses", {})
            sub = subs.setdefault(sub_slug, {})
            feats = sub.setdefault("features", {})
            entry = feats.setdefault(name_en, {})
        else:
            print(f"Chiave non riconosciuta: {key}")
            continue
        if entry.get("description"):
            updated += 1
        else:
            added += 1
        entry["description"] = desc
    PATH.write_text(json.dumps(current, ensure_ascii=False, indent=2), encoding="utf-8")
    print(f"Inserite {len(NEW_TRANSLATIONS)} traduzioni ({added} nuove, {updated} aggiornate).")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
